mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM posts p
    WHERE p.post_id = #{postId}
      AND p.deleted_at IS NULL
)

SELECT c.comment_id, u.user_id, u.nickname, u.profile_image, c.content, c.like_count, EXISTS( SELECT 1 FROM comment_likes cl WHERE cl.comment_id = c.comment_id AND cl.user_id = #{userId} ) AS liked_by_me, c.created_at, c.parent_id FROM comments c JOIN users u ON u.user_id = c.user_id WHERE c.post_id = #{postId} AND c.parent_id IS NULL AND c.deleted_at IS NULL AND u.deleted_at IS NULL
AND (c.created_at, c.comment_id) < (#{createdAt}, #{commentId})
ORDER BY c.created_at DESC, c.comment_id DESC LIMIT #{size}

SELECT c.comment_id, u.user_id, u.nickname, u.profile_image, c.content, c.like_count, EXISTS( SELECT 1 FROM comment_likes cl WHERE cl.comment_id = c.comment_id AND cl.user_id = #{userId} ) AS liked_by_me, c.created_at, c.parent_id FROM comments c JOIN users u ON u.user_id = c.user_id WHERE c.parent_id IN
#{parentId}
AND c.deleted_at IS NULL AND u.deleted_at IS NULL ORDER BY c.parent_id, c.created_at DESC, c.comment_id DESC
